# == Backend object for js page ==
class Backend(QObject):
    def __init__(self,parent):
        super().__init__()
        self.page = parent.page()
        self.pa_ = parent
        self.tasks = []
    @Slot()
    def mor_candales(self):
        if len(self.tasks) == 0 and self.pa_.ready == True:
            self.tasks.append(asyncio.create_task(self.pa_._load_candales(te="M")))
        self.tasks = [t for t in self.tasks if not t.done()]
        log_("debug",f"Added more candals to {self.pa_.SYMBOL}",source="Backend.mor_candales")

def critical_error_(ntype:str,source:str=""):
    """
    Specific critical errors function for this file
    """
    critical_error(ntype, f"charts.candals_shart.{source}")

def error_(etype,source:str,msg:str):
    """
    Specific general errors function for this file
    """
    error(etype, f"charts.candals_shart.{source}", msg)

def log_(ltype:str,msg:str,source:str=""):
    """
    Specific log function for this file
    """
    log(ltype,msg, f"charts.candals_shart.{source}")



# ==================================================================
# Main class
# ==================================================================
class SimpleCandelsChart(QWebEngineView):
    def __init__(self,time_frame: str = "4h",symbol: str = "SOLUSDT"):
        """Initialize the Home Page with chart settings."""

        # == Chart Settings ==
        self.FRAME = to_milliseconds(time_frame)
        self.SYMBOL = symbol + "USDT"
        self.ready = False

        # == Set Channel and Parent Init == 
        super().__init__()
        self.channel = QWebChannel(self)
        self.backend = Backend(self)
        self.channel.registerObject("backend",self.backend)
        self.page().setWebChannel(self.channel)

        # == Variables ==
        self.async_tasks = []
        log_("info",f"Start candals chart for {self.SYMBOL}","SimpleCandelsChart.closeEvent")
        self.session = aiohttp.ClientSession()
        self.symbol_obj = OneSymbole(symbol=self.SYMBOL,errors_queue=Connection_errors)
        AsyncController.window_m(self,"add")
        AsyncController.rest_m(self.session,'add')

        # == Chart Variables ==
        html = base64.b64decode(pp.encode()).decode()
        self.setMinimumHeight(400)
        self.setHtml(html)
        self.setContextMenuPolicy(Qt.CustomContextMenu)
        self.customContextMenuRequested.connect(self.show_context_menu)
        self.resize(900, 560)
        self.setWindowTitle(f"{self.SYMBOL} Price")
        asyncio.create_task(self.symbol_obj.start(self.session))


        self.loadFinished.connect(lambda ok: self.run_(ok))

    # ==== Click-right-list =====
    def show_context_menu(self, pos):
        menu = QMenu(self)
        reload_action = QAction("Reload", self)
        reload_action.triggered.connect(self.reload)
        back_action = QAction("Back", self)
        back_action.triggered.connect(self.back)
        forward_action = QAction("Forward", self)
        forward_action.triggered.connect(self.forward)
        menu.addAction(back_action)
        menu.addAction(forward_action)
        menu.addSeparator()
        menu.addAction(reload_action)
        menu.exec_(self.mapToGlobal(pos))

    # ======== Update Price via WebSocket ==============
    async def update_price(self):
        """Listen for live price updates via WebSocket with error handling."""
        async for message in self.symbol_obj.klines_stream(self.FRAME[1]):
            asyncio.create_task(self._draw_updated_candel(message))
        

    # ======== Draw Updated Candel ==============
    async def _draw_updated_candel(self, message):
        """Update the chart with new candle data."""
        open_time = message['open_time']
        open_price = float(message['open'])
        high_price = float(message['high'])
        low_price = float(message['low'])
        close_price = float(message['close'])
        volume = float(message['volume'])
        close_time = message['close_time']

        new_candle = f'''
                timestamp: {open_time},          // Strat time of candal by ms
                open: {open_price},              // open price
                high: {high_price},              // max price
                low: {low_price},                // min price
                close: {close_price},            // close price
                volume: {volume},                // trade volume
        '''

        self.page().runJavaScript('chart.updateData({new_candle});'.replace("new_candle", new_candle))

    # ======== Fetch Klines ==============
    async def __get_klines(self,endt:int=None):
        """Fetch historical kline data from Binance REST API."""
        url = "https://api.binance.com/api/v3/klines"
        log_("debug","Fetching klines from Binance REST API...","SimpleCandelsChart.__get_klines")
        params = {
            "symbol": self.SYMBOL.upper(),
            "interval": self.FRAME[1],
            "limit": 1000
        }
        if endt:
            params["endTime"] = endt
        
        async with self.session.get(url, params=params) as r:
            if r.status == 429:self.close(); return critical_error_("429","SimpleCandelsChart.__get_klines")
            if r.status == 418:self.close(); return critical_error_("418","SimpleCandelsChart.__get_klines")
            if r.status == 403:self.close(); return critical_error_("403","SimpleCandelsChart.__get_klines")
            if r.status == 200:
                data = await r.json()
                self.first_candal_time = int(data[0][0])
                return data
            else:
                error_(f"CONNECTION_{r.status}","SimpleCandelsChart.__get_klines",f"Failed to fetch klines: {r.status}")
                return []

    # ======== First Data Loading ==============
    async def _load_candales(self,te="N"):
        """Load initial candle data from Binance REST API with error handling."""
        try:
            log_("debug","Loading initial candle data...","SimpleCandelsChart._load_candales")
            if te == "N":kligns = await self.__get_klines()
            elif te == "M":kligns = await self.__get_klines(endt=self.first_candal_time)

            self.df = pd.DataFrame(kligns,columns=[
                "open_time", "open", "high", "low", "close", "volume",
                "close_time", "quote_asset_volume", "number_of_trades",
                "taker_buy_base_asset_volume", "taker_buy_quote_asset_volume", "ignore"
            ])
            for col in ["open_time", "close_time", "open", "high", "low", "close","volume", "quote_asset_volume", "taker_buy_base_asset_volume","taker_buy_quote_asset_volume"]:
                self.df[col] = self.df[col].astype(float)

            log_("debug","Initial candle data loaded successfully.","SimpleCandelsChart._load_candales")

            # Prepare JavaScript array of candles
            log_("debug","Preparing JavaScript array of candles...","SimpleCandelsChart._load_candales")
            candles_list = []
            for row in self.df.itertuples():  # rows هي بيانات الشموع من DB أو API
                candles_list.append({
                    "timestamp": row.open_time,
                    "open": row.open,
                    "high": row.high,
                    "low": row.low,
                    "close": row.close,
                    "volume": row.volume
                })
            candles_list.pop(-1) # Remove the last candle if it's still forming
            candles_js_array = json.dumps(candles_list)

            # Apply candles data to chart
            log_("debug","Applying candles data to chart...","SimpleCandelsChart._load_candales")
            if te == "N": 
                self.page().runJavaScript(f'chart.applyNewData({candles_js_array});')
                self.ready = True
            elif te == "M": self.page().runJavaScript(f'chart.applyMoreData({candles_js_array});')

            log_("debug","Candles data applied to chart.","SimpleCandelsChart._load_candales")
        except Exception as e:
            error_(e,"SimpleCandelsChart._load_candales",str(e))


    # ======== Infrastructure defs ==============
    # on close window
    def closeEvent(self, event):
        asyncio.create_task(self.close())
        AsyncController.window_m(self,'delete')
        AsyncController.rest_m(self.session,'delete')
        log_("info",f"Close candals chart for {self.SYMBOL}","SimpleCandelsChart.closeEvent")
        event.accept()

    async def close(self):
        try:
            await self.session.close()
            await self.symbol_obj.close()
            for i in self.async_tasks:
                try:
                    i.cancel()
                except: 
                    pass
        except:
            pass

    # Start all functions and show window
    async def _start(self):
        await self._load_candales()

    # ======== Run Window ==============
    def run_(self,ok):
        if ok:
            self.async_tasks.append(asyncio.create_task(self._start()))
            self.async_tasks.append(asyncio.create_task(self.update_price()))
            self.show()
    
    def run(self):
        self.show()


    # ======== Static Methods ==============
    # Set all vars and widgets that SimpleCandelsChart in chowCharts
    @staticmethod
    def set_chart_vars(parent):
        SimpleCandelsChart.mainchart_items = {}
        

    # Reset ChowCharts When the olugin seted
    @staticmethod
    def reset_showchart_body(parent):
        parent._hide_all()
        parent.time_frame["label"].setText("Time frame")
        parent.setFixedSize(300, 155)
        parent.submit_button.setGeometry(5, 110, 290, 35)
        parent.time_frame["label_bottum"].setText("Binance candals intervals")
        parent.time_frame["main_list"].clear()
        parent.time_frame["main_list"].addItems(TIME_FRAMES_INTERVALS)
        parent.time_frame["main_list"].show()

        parent.spot_symbols = ALL_USDT_SYMBOLS

        parent.time_frame['is_correct'] = True

    # Creat the shart wen Add Button in show shart pushed
    @staticmethod
    def submit_data(parent,chart):
        parent.time_frame_value = parent.time_frame["main_list"].currentText()
        w = chart(symbol=parent.symbol_value,time_frame=parent.time_frame_value)
        parent.windows.append(w)
        w.run()


